#include <XSegment_lib.h>

XSeg_HT16K33 display(0x70);

void setup() {
  Serial.begin(115200);
  Wire.begin();
  display.begin();
  display.setBrightness(7);

  Serial.println("=== HT16K33 Demo ===");
}

void loop() {
  static int counter = 0;

  // 16-digit display
  display.show(counter);
  Serial.print("Display: "); Serial.println(counter);
  counter++;
  delay(300);

  // String
  display.show("16 DIGIT DISPLAY");
  Serial.println("Display: 16 DIGIT DISPLAY");
  delay(500);

  // Float
  display.show(123.456f, 3);
  Serial.println("Display: 123.456");
  delay(500);

  // Clear
  display.clear();
  delay(200);
}
